<?php
namespace App\Domain\Loans\Actions;
use App\Enums\LoanApplicationStatus;use App\Models\LoanApplication;use App\Models\LoanProduct;use App\Models\Member;use Illuminate\Support\Facades\Auth;use Illuminate\Support\Str;use Illuminate\Validation\ValidationException;
class CreateLoanApplication{public function execute(Member $member,LoanProduct $product,array $data):LoanApplication{if(!$product->is_active)throw ValidationException::withMessages(['loan_product_id'=>['The loan product is inactive.']]);if($data['requested_principal_minor']<$product->minimum_principal_minor||$data['requested_principal_minor']>$product->maximum_principal_minor)throw ValidationException::withMessages(['requested_principal_minor'=>['Requested principal is outside product limits.']]);if($data['tenure']<$product->minimum_tenure||$data['tenure']>$product->maximum_tenure)throw ValidationException::withMessages(['tenure'=>['Requested tenure is outside product limits.']]);if(isset($data['preferred_bank_account_id'])&&!$member->bankAccounts()->whereKey($data['preferred_bank_account_id'])->exists())throw ValidationException::withMessages(['preferred_bank_account_id'=>['The bank account does not belong to this member.']]);return LoanApplication::query()->create(['member_id'=>$member->id,'loan_product_id'=>$product->id,'approval_workflow_id'=>$product->approval_workflow_id,'reference'=>'LAP-'.strtoupper(Str::ulid()),'requested_principal_minor'=>$data['requested_principal_minor'],'tenure'=>$data['tenure'],'purpose'=>$data['purpose'],'preferred_bank_account_id'=>$data['preferred_bank_account_id']??null,'status'=>LoanApplicationStatus::Draft,'applicant_snapshot'=>['membership_number'=>$member->membership_number,'name'=>trim($member->first_name.' '.$member->last_name),'member_category_id'=>$member->member_category_id,'date_joined'=>$member->date_joined?->toDateString()],'created_by'=>Auth::id()]);}}
